import { Component, Element, h, Listen, Prop, State, Watch } from '@stencil/core';

@Component({
  tag: 'wdpr-media-player',
  styleUrl: 'wdpr-media-player.css',
  shadow: true,
})
export class WdprMediaPlayer {
  private videoEl?: HTMLVideoElement;
  private trackEl?: HTMLTrackElement;
  private autoHideControlTimer?: number;

  @Element() host!: HTMLElement;

  @State() _playing = false;
  @State() _muted = false;
  @State() _currentTime = 0;
  @State() _duration = 0;
  @State() _captionsEnabled = false;
  @State() _isFullscreen = false;
  @State() _activeCaption = '';
  @State() _controlIdle = false;
  @State() _isVertical = false;

  @Prop() src!: string;
  @Prop() poster?: string;
  @Prop() captionsSrc?: string;
  @Prop() captionsLang = 'en';
  @Prop() captionsLabel = 'CC';
  @Prop() autoHideMs = 2000;
  @Prop() showControls = true;
  @Prop() showTime = true;
  @Prop() showCaptionsToggle = true;
  @Prop() showMuteToggle = true;
  @Prop() showFullscreenButton = true;
  @Prop() showPlayToggleOnControl = true;
  @Prop() showProgressBar = true;
  @Prop() showAudioChip = false;
  @Prop() captionsPosition: 'top' | 'bottom' = 'top';
  @Prop() loading = false;

  @Watch('playing')
  onPlayingChange(isPlaying: boolean) {
    if (!isPlaying) {
      this._controlIdle = false;
      this._clearAutoHideTimer();
    } else {
      this._showControlsTemporarily();
    }
  }

  @Listen('wdprPlayToggle')
  onPlayToggle() {
    this._togglePlay();
    this._showControlsTemporarily();
  }

  @Listen('wdprMuteToggle')
  onMuteToggle() {
    this._toggleMute();
    this._showControlsTemporarily();
  }

  @Listen('wdprCaptionsToggle')
  onCaptionsToggle() {
    this._captionsEnabled = !this._captionsEnabled;
    this._showControlsTemporarily();
  }

  @Listen('wdprBarTimeChange')
  onProgressBarTimeChange(timeChangeEvent: CustomEvent<{ time: number }>) {
    this._progressBarTimeChange(timeChangeEvent.detail.time);
    this._showControlsTemporarily();
  }

  @Listen('wdprFullscreenToggle')
  onFullscreenToggle() {
    this._toggleFullscreen();
    this._showControlsTemporarily();
  }

  componentDidLoad() {
    this.videoEl = this.host.shadowRoot?.querySelector('video') ?? undefined;
    this.trackEl = this.host.shadowRoot?.querySelector('track') ?? undefined;

    if (!this.videoEl) return;

    this.videoEl.addEventListener('loadedmetadata', this._onLoadedMetadata);
    this.videoEl.addEventListener('timeupdate', this._syncFromVideo);
    this.videoEl.addEventListener('play', this._syncFromVideo);
    this.videoEl.addEventListener('pause', this._syncFromVideo);
    this.videoEl.addEventListener('volumechange', this._syncFromVideo);

    document.addEventListener('fullscreenchange', this._onFullscreenChange);

    this._setupCaptionsOverlay();
    this._syncFromVideo();
  }

  disconnectedCallback() {
    this._clearAutoHideTimer();
    this._teardownCaptionsOverlay();
    document.removeEventListener('fullscreenchange', this._onFullscreenChange);
  }

  private _onLoadedMetadata = () => {
    const videoElement = this.videoEl;
    if (!videoElement) return;

    this._isVertical = videoElement.videoHeight > videoElement.videoWidth;

    this._syncFromVideo();
  };

  private _showControlsTemporarily() {
    this._controlIdle = false;
    this._resetAutoHide();
  }

  private _resetAutoHide() {
    this._clearAutoHideTimer();
    if (!this._playing) return;

    this.autoHideControlTimer = window.setTimeout(() => {
      if (this._playing) this._controlIdle = true;
    }, this.autoHideMs);
  }

  private _clearAutoHideTimer() {
    if (this.autoHideControlTimer) window.clearTimeout(this.autoHideControlTimer);
    this.autoHideControlTimer = undefined;
  }

  private _onPlayerClick = (e: MouseEvent) => {
    const path = (e.composedPath?.() ?? []) as HTMLElement[];
    const clickedControl = path.some(el => el?.tagName?.toLowerCase() === 'wdpr-media-player-control');
    if (!clickedControl) this._showControlsTemporarily();
  };

  private _syncFromVideo = () => {
    const videoElement = this.videoEl;
    if (!videoElement) return;

    this._playing = !videoElement.paused && !videoElement.ended;
    this._muted = videoElement.muted || videoElement.volume === 0;
    this._currentTime = videoElement.currentTime || 0;
    this._duration = Number.isFinite(videoElement.duration) ? videoElement.duration : 0;
    this._isFullscreen = !!document.fullscreenElement;
  };

  private _togglePlay = async () => {
    const videoElement = this.videoEl;
    if (!videoElement) return;

    if (videoElement.paused) {
      await videoElement.play();
    } else {
      videoElement.pause();
    }
  };

  private _toggleMute = () => {
    if (this.videoEl) this.videoEl.muted = !this.videoEl.muted;
  };

  private _progressBarTimeChange(time: number) {
    if (!this.videoEl) return;
    this.videoEl.currentTime = Math.min(Math.max(time, 0), this._duration || 0);
  }

  private _toggleFullscreen = async () => {
    const videoElement = this.videoEl as HTMLVideoElement & { webkitEnterFullscreen?: () => void };
    if (!videoElement) return;

    if (typeof videoElement.webkitEnterFullscreen === 'function') {
      videoElement.webkitEnterFullscreen();

      return;
    }

    const container = this.host.shadowRoot?.querySelector('.player') as HTMLElement | null;
    if (!container) return;

    if (!document.fullscreenElement) await container.requestFullscreen();
    else await document.exitFullscreen();
  };

  private _onFullscreenChange = () => {
    this._isFullscreen = !!document.fullscreenElement;
  };

  /* ---------------- captions ---------------- */

  private _onCueChange = () => {
    if (!this._captionsEnabled) {
      this._activeCaption = '';
      
      return;
    }

    const cues = this.trackEl?.track?.activeCues;
    const cue = cues && cues.length ? (cues[0] as VTTCue) : null;
    this._activeCaption = cue?.text ?? '';
  };

  private _setupCaptionsOverlay() {
    if (!this.trackEl?.track) return;
    this.trackEl.track.mode = 'hidden';
    this.trackEl.track.addEventListener('cuechange', this._onCueChange);
  }

  private _teardownCaptionsOverlay() {
    this.trackEl?.track?.removeEventListener('cuechange', this._onCueChange);
  }

  render() {
    const captionsPositionClasses = this.captionsPosition === 'top' ? 'top-250' : this._isVertical ? 'bottom-24' : 'bottom-14';

    return (
      <div
        class={{
          'player relative isolate w-full overflow-hidden': true,
          'control-idle': this._playing && this._controlIdle,
          'pointer-events-none': this.loading,
        }}
        aria-busy={this.loading}
        onMouseMove={() => this._showControlsTemporarily()}
        onMouseDown={() => this._showControlsTemporarily()}
        onKeyDown={() => this._showControlsTemporarily()}
        onClick={this._onPlayerClick}
        onTouchStart={() => this._showControlsTemporarily()}
      >
        {this.loading && (
          <span role="status" aria-live="polite" class="sr-only">
            Loading media player
          </span>
        )}
        <div
          class={{
            'relative w-full': true,
            'max-h-screen': this._isVertical,
          }}
          style={{
            aspectRatio: this._isVertical ? '9 / 16' : '16 / 9',
          }}
          inert={this.loading ? true : undefined}
        >
          <video
            ref={el => (this.videoEl = el as HTMLVideoElement)}
            class={{
              'absolute inset-0 h-full w-full': true,
              'object-cover': !this._isVertical,
              'object-contain bg-black': this._isVertical,
            }}
            src={this.src}
            poster={this.poster}
            playsInline
          >
            {this.captionsSrc ? (
              <track ref={el => (this.trackEl = el as HTMLTrackElement)} kind="captions" src={this.captionsSrc} srcLang={this.captionsLang} label={this.captionsLabel} default />
            ) : null}
          </video>

          {this._captionsEnabled && this._activeCaption ? (
            <div 
              class={`pointer-events-none absolute inset-x-0 z-30 flex justify-center ${captionsPositionClasses}`}
            >
              <div class="captions">{this._activeCaption}</div>
            </div>
          ) : null}

          {this.showAudioChip && <wdpr-media-player-control-mute-toggle class="absolute bottom-200 right-200 audio-chip" muted={this._muted} variant="overlay" />}

          {this.loading && (
            <div class="absolute inset-0 z-30 flex items-center justify-center pointer-events-none bg-page-overlay-disabled">
              <wdpr-radial-loader showLabel={false} size="medium"></wdpr-radial-loader>
            </div>
          )}

          <wdpr-media-player-control
            class="absolute inset-0 z-20 transition-opacity duration-200 controls"
            playing={this._playing}
            muted={this._muted}
            isFullscreen={this._isFullscreen}
            captionsEnabled={this._captionsEnabled}
            currentTime={this._currentTime}
            duration={this._duration}
            showControls={this.showControls}
            showTime={this.showTime}
            showCaptionsToggle={this.showCaptionsToggle}
            showMuteToggle={this.showMuteToggle}
            showFullscreenButton={this.showFullscreenButton}
            showPlayToggleOnControl={this.showPlayToggleOnControl}
            showProgressBar={this.showProgressBar}
            vertical={this._isVertical}
            loading={this.loading}
          />
        </div>
      </div>
    );
  }
}
